biz_ratings = {}
for rev in reviews:
    gid = rev['gmap_id']
    rating = int(rev['rating'])

    if gid not in biz_ratings:
        biz_ratings[gid] = []
    biz_ratings[gid].append(rating)

avg_ratings = {gid: sum(r)/len(r) for gid, r in biz_ratings.items()}

# Parse hours to find businesses open after 6 PM on weekdays
weekdays = ['Monday','Tuesday','Wednesday','Thursday','Friday']

def time_to_minutes(t):
    t = t.strip().upper()
    if t in ['CLOSED','OPEN 24 HOURS']:
        return None
    m = re.match(r'(\d{1,2})(?::(\d{2}))?\s*(AM|PM)', t)
    if not m:
        return None
    h = int(m.group(1))
    minute = int(m.group(2)) if m.group(2) else 0
    if m.group(3) == 'PM' and h != 12:
        h += 12
    elif m.group(3) == 'AM' and h == 12:
        h = 0
    return h * 60 + minute

def check_open_late(hours_str):
    if not hours_str or hours_str == 'None':
        return False
    try:
        hrs = eval(hours_str)
        for day_info in hrs:
            if len(day_info) != 2:
                continue
            day, rng = day_info
            if day not in weekdays:
                continue
            if rng == 'Closed':
                continue
            if rng == 'Open 24 hours':
                return True
            if '–' in rng:
                parts = rng.split('–')
                if len(parts) == 2:
                    close = time_to_minutes(parts[1])
                    if close and close > 18 * 60:  # 6 PM
                        return True
    except:
        pass
    return False

# Find qualified businesses
qualified = []
for b in businesses:
    if check_open_late(b['hours']):
        gid = b['gmap_id']
        qualified.append({
            'name': b['name'],
            'hours': b['hours'],
            'avg_rating': avg_ratings.get(gid, 0),
            'review_count': len(biz_ratings.get(gid, []))
        })

# Sort by rating and get top 5
top5 = sorted(qualified, key=lambda x: x['avg_rating'], reverse=True)[:5]

result = {
    'businesses': [
        {
            'name': b['name'],
            'operating_hours': b['hours'],
            'average_rating': round(b['avg_rating'], 2),
            'review_count': b['review_count']
        }
        for b in top5
    ],
    'total_found': len(qualified)
}

print('__RESULT__:')
print(json.dumps(result, indent=2))

